import{_ as i,o as t,c as o,a4 as a}from"./chunks/framework.ChErgFjV.js";const p=JSON.parse('{"title":"《麦肯锡精英的48个工作习惯》读书笔记","description":"","frontmatter":{},"headers":[],"relativePath":"study/reading-notes/20260713-《麦肯锡精英的48个工作习惯》读书笔记.md","filePath":"study/reading-notes/20260713-《麦肯锡精英的48个工作习惯》读书笔记.md","lastUpdated":1783931283000}'),u={name:"study/reading-notes/20260713-《麦肯锡精英的48个工作习惯》读书笔记.md"};function r(e,l,q,n,h,d){return t(),o("div",null,[...l[0]||(l[0]=[a('<h1 id="《麦肯锡精英的48个工作习惯》读书笔记" tabindex="-1">《麦肯锡精英的48个工作习惯》读书笔记 <a class="header-anchor" href="#《麦肯锡精英的48个工作习惯》读书笔记" aria-label="Permalink to &quot;《麦肯锡精英的48个工作习惯》读书笔记&quot;">​</a></h1><blockquote><p><strong>书籍信息</strong></p><ul><li>书名：麦肯锡精英的48个工作习惯</li><li>作者：[日]户塚隆将</li><li>出版社：中信出版集团</li><li>阅读时间：2026年7月13日</li><li>分类：💼 职场发展</li></ul></blockquote><blockquote><p><strong>读者背景</strong></p><ul><li>17年软件开发经验，技术总监/项目管理/部门经理</li><li>带过20+人项目和30+人部门</li><li>两个孩子父亲</li><li>因家庭和个人身体精力原因想了解其他行业或寻求改变</li></ul></blockquote><hr><h2 id="一、核心观点" tabindex="-1">一、核心观点 <a class="header-anchor" href="#一、核心观点" aria-label="Permalink to &quot;一、核心观点&quot;">​</a></h2><p>本书作者户塚隆将曾在高盛集团、哈佛商学院、麦肯锡咨询公司三家顶级机构工作，他总结出世界精英们共通的48个工作习惯，归纳为四大成功要素：</p><h3 id="四大成功要素框架" tabindex="-1">四大成功要素框架 <a class="header-anchor" href="#四大成功要素框架" aria-label="Permalink to &quot;四大成功要素框架&quot;">​</a></h3><table tabindex="0"><thead><tr><th>成功要素</th><th>核心内涵</th><th>涵盖习惯数</th></tr></thead><tbody><tr><td>重视人脉投资</td><td>珍惜超越利害关系的人脉，主动拓展人际关系</td><td>约12个</td></tr><tr><td>不断充实内在与外在</td><td>思考能力、身体素质、仪表形象的综合提升</td><td>约12个</td></tr><tr><td>保证每天定量完成任务</td><td>时间管理、效率提升、工作习惯养成</td><td>约12个</td></tr><tr><td>以宏观眼光看问题</td><td>全球化视野、职业规划、目标管理</td><td>约12个</td></tr></tbody></table><h3 id="六章结构精华" tabindex="-1">六章结构精华 <a class="header-anchor" href="#六章结构精华" aria-label="Permalink to &quot;六章结构精华&quot;">​</a></h3><p><strong>第一章：如何投资人脉</strong></p><ul><li>人脉的本质是&quot;connecting the dots&quot;——把生命点滴串联起来</li><li>珍惜超越利害关系的人脉，相信直觉、命运、缘分</li><li>记住对方姓名是拓展人脉的根本（见面时称呼对方名字三次）</li><li>每周至少与公司以外的人见一次面</li></ul><p><strong>第二章：磨炼内在与外在</strong></p><ul><li>读书后要花三倍时间思考（麦肯锡读书术：1:3法则）</li><li>培养解决&quot;无固定答案问题&quot;的习惯</li><li>&quot;空→雨→伞&quot;思考模式：观察事实→推导结论→采取行动</li><li>用&quot;三个关键&quot;锻炼瞬间思考能力</li><li>保持强健体魄：充足睡眠、吃早餐、定期运动</li></ul><p><strong>第三章：养成不被时间操纵的工作习惯</strong></p><ul><li>无论何时都要提前10分钟到场</li><li>充分利用清晨一小时的高效时间（不先查看邮件）</li><li>下班前整理第二天工作计划</li><li>周一提前15分钟起床，周日晚上做好准备</li><li>工作忙时按优先程度和时间分类处理：A→B→A→C→D</li></ul><p><strong>第四章：决定性的沟通创造出成果</strong></p><ul><li>笔记本随时放在三秒可打开的地方</li><li>接到任务当场确认任务信息（5W1H）</li><li>回复邮件速度=别人对你的评价</li><li>汇报、联系、交谈时要先发制人（不让上司先问）</li><li>接到任务即使只完成70%，第二天一早也要汇报</li></ul><p><strong>第五章：在资料和会议方面做出贡献</strong></p><ul><li>将资料视作&quot;自己的产品&quot;</li><li>准备资料要有&quot;3W&quot;意识：Who、What、Why</li><li>手写草稿比直接用PPT更高效</li><li>会议不发言等于缺席，要主动贡献价值</li><li>善用白板整理讨论要点</li></ul><p><strong>第六章：提高全球化的职业技能</strong></p><ul><li>健全的爱国心可转化为动力源泉</li><li>英语表达逻辑性比流利更重要</li><li>托福900分是商务英语的入门标准</li><li>工作时以更高标准要求自己（晋升前先展示能力）</li><li>辞职不是&quot;退学&quot;，要争取&quot;毕业&quot;</li></ul><hr><h2 id="二、启发思考" tabindex="-1">二、启发思考 <a class="header-anchor" href="#二、启发思考" aria-label="Permalink to &quot;二、启发思考&quot;">​</a></h2><h3 id="_1-关于人脉的本质认知" tabindex="-1">1. 关于人脉的本质认知 <a class="header-anchor" href="#_1-关于人脉的本质认知" aria-label="Permalink to &quot;1. 关于人脉的本质认知&quot;">​</a></h3><p>作者借用乔布斯&quot;connecting the dots&quot;的概念重新定义人脉：</p><blockquote><p>&quot;你会在无意中结交朋友，却不能预见你们的关系在将来会如何发展......你要相信直觉、命运、人生、缘分等。对超越利害关系的人脉保持信赖，人际关系就会得到发展。&quot;</p></blockquote><p><strong>我的思考</strong>： 这打破了功利性社交的思维定式。17年职场生涯中，我积累了不少人脉，但往往带有项目合作的目的性。真正的长期人脉投资，应该是：</p><ul><li>在没有直接利益时也愿意投入时间和情感</li><li>相信某些连接会在未来某个时刻串联起来</li><li>带着感恩之心维系关系</li></ul><h3 id="_2-关于思考与信息的区分" tabindex="-1">2. 关于思考与信息的区分 <a class="header-anchor" href="#_2-关于思考与信息的区分" aria-label="Permalink to &quot;2. 关于思考与信息的区分&quot;">​</a></h3><p>作者强调&quot;思考和查找大不相同&quot;：</p><blockquote><p>&quot;不依赖他人的经验，从零思考也能让人们拥有新的想法......思考就像一日三餐，俨然已经成为习惯。&quot;</p></blockquote><p><strong>我的思考</strong>： 作为技术管理者，我习惯快速检索解决方案。但真正的价值创造需要独立思考：</p><ul><li>遇到问题先暂停5分钟，用纸笔思考而非立即搜索</li><li>区分&quot;获取信息&quot;和&quot;形成见解&quot;两个阶段</li><li>用&quot;So what?&quot;和&quot;Why so?&quot;深挖问题本质</li></ul><h3 id="_3-关于时间管理的本质" tabindex="-1">3. 关于时间管理的本质 <a class="header-anchor" href="#_3-关于时间管理的本质" aria-label="Permalink to &quot;3. 关于时间管理的本质&quot;">​</a></h3><p>作者提出早晨一小时的黄金法则：</p><blockquote><p>&quot;清晨的办公室非常安静，不会被任何人打扰，是唯一一个几乎能100%投入到工作的时间段。&quot;</p></blockquote><p><strong>我的思考</strong>： 作为带两个孩子的父亲，早晨确实是最宝贵的独处时间。我应该：</p><ul><li>重新规划晨间时间，用于深度思考而非回复邮件</li><li>下班前做好第二天计划，减少早晨的混乱</li><li>把操作性工作安排在下午低效时段</li></ul><h3 id="_4-关于职业转换的心态" tabindex="-1">4. 关于职业转换的心态 <a class="header-anchor" href="#_4-关于职业转换的心态" aria-label="Permalink to &quot;4. 关于职业转换的心态&quot;">​</a></h3><p>作者用&quot;毕业&quot;而非&quot;退学&quot;来比喻辞职：</p><blockquote><p>&quot;辞职时，即使不能得到公司所有同事的支持，至少也要得到部分人的支持......前任同事是宝贵的财产。&quot;</p></blockquote><p><strong>我的思考</strong>： 这正是我目前状态需要的认知。考虑职业转型时：</p><ul><li>不能抱着&quot;逃避&quot;心态离开</li><li>要在当前岗位上留下可传承的成果</li><li>维护好与前同事的关系网络</li><li>让转型成为主动选择而非被动逃离</li></ul><hr><h2 id="三、专属建议-结合17年技术管理-二孩父亲背景" tabindex="-1">三、专属建议（结合17年技术管理+二孩父亲背景） <a class="header-anchor" href="#三、专属建议-结合17年技术管理-二孩父亲背景" aria-label="Permalink to &quot;三、专属建议（结合17年技术管理+二孩父亲背景）&quot;">​</a></h2><h3 id="人生发展维度" tabindex="-1">人生发展维度 <a class="header-anchor" href="#人生发展维度" aria-label="Permalink to &quot;人生发展维度&quot;">​</a></h3><ol><li><p><strong>重新定义&quot;精英&quot;标准</strong></p><ul><li>不再以加班时长、项目数量衡量成功</li><li>将&quot;可持续成长&quot;作为新的人生指标</li><li>48个习惯中筛选出适合当前阶段的核心习惯</li></ul></li><li><p><strong>建立&quot;私人笔记&quot;系统</strong></p><ul><li>随身携带笔记本，记录中长期目标</li><li>多次书写相同目标，让目标内化于心</li><li>在迷茫时翻看笔记，找回方向感</li></ul></li><li><p><strong>把健康管理放在首位</strong></p><ul><li>每天保证6-7小时睡眠（作者强调这是基础）</li><li>周末固定运动时间，向家人承诺形成约束</li><li>定期体检，接种疫苗，预防性地维护身体</li></ul></li></ol><h3 id="家庭关系维度" tabindex="-1">家庭关系维度 <a class="header-anchor" href="#家庭关系维度" aria-label="Permalink to &quot;家庭关系维度&quot;">​</a></h3><ol><li><p><strong>平衡工作与生活的阶段性策略</strong></p><ul><li>作者建议：20多岁全力投入工作，30多岁周末半天自我投资</li><li>作为40+岁的父亲，可以调整为：工作日高效产出，周末家庭优先</li><li>把与家人的相处时间也视为&quot;人脉投资&quot;</li></ul></li><li><p><strong>在不同环境与家人相处</strong></p><ul><li>作者强调&quot;变换场合&quot;能加深关系</li><li>与家人不只在家里相处，也安排户外活动、旅行</li><li>创造不同场景的家庭记忆</li></ul></li><li><p><strong>礼让精神的家庭实践</strong></p><ul><li>将&quot;礼让他人&quot;的习惯延伸到家庭</li><li>对孩子展示尊重他人的榜样</li><li>用行动而非语言传递价值观</li></ul></li></ol><h3 id="事业发展维度" tabindex="-1">事业发展维度 <a class="header-anchor" href="#事业发展维度" aria-label="Permalink to &quot;事业发展维度&quot;">​</a></h3><ol><li><p><strong>从&quot;执行者&quot;到&quot;战略者&quot;的转型</strong></p><ul><li>减少操作性工作占比</li><li>用清晨一小时做战略思考</li><li>培养&quot;宏观眼光看问题&quot;的能力</li></ul></li><li><p><strong>人脉的二次开发</strong></p><ul><li>重新激活17年积累的人脉资源</li><li>每周至少与一位行业外人士交流</li><li>通过朋友介绍认识新领域的从业者</li></ul></li><li><p><strong>提升表达与资料能力</strong></p><ul><li>用&quot;三个关键&quot;框架整理发言要点</li><li>手写草稿再数字化，提升思考质量</li><li>将资料视为&quot;产品&quot;，注重细节和统一感</li></ul></li><li><p><strong>职业转型的准备</strong></p><ul><li>设定转型的中长期目标并写下来</li><li>保持英语学习（托福900分目标）</li><li>在现有岗位上留下&quot;毕业证书&quot;</li></ul></li></ol><h3 id="小孩子教育维度" tabindex="-1">小孩子教育维度 <a class="header-anchor" href="#小孩子教育维度" aria-label="Permalink to &quot;小孩子教育维度&quot;">​</a></h3><ol><li><p><strong>培养孩子的思考习惯</strong></p><ul><li>鼓励孩子面对&quot;无固定答案的问题&quot;</li><li>不只问&quot;答案是什么&quot;，更要问&quot;你怎么想的&quot;</li><li>用&quot;So what?&quot;引导孩子深挖原因</li></ul></li><li><p><strong>人脉意识的早期启蒙</strong></p><ul><li>教导孩子记住他人名字的重要性</li><li>鼓励孩子主动打招呼、表达感谢</li><li>让孩子理解&quot;朋友会在未来串联起来&quot;</li></ul></li><li><p><strong>礼让与感恩的教育</strong></p><ul><li>区分&quot;对不起&quot;和&quot;谢谢&quot;的使用场景</li><li>在家庭中实践礼让行为</li><li>用行动展示对他人的尊重</li></ul></li><li><p><strong>健康习惯的养成</strong></p><ul><li>确保孩子充足睡眠</li><li>建立固定的运动习惯</li><li>从小培养时间观念</li></ul></li></ol><hr><h2 id="四、行动计划" tabindex="-1">四、行动计划 <a class="header-anchor" href="#四、行动计划" aria-label="Permalink to &quot;四、行动计划&quot;">​</a></h2><h3 id="立即执行-本周内" tabindex="-1">立即执行（本周内） <a class="header-anchor" href="#立即执行-本周内" aria-label="Permalink to &quot;立即执行（本周内）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行动项</th><th>具体做法</th><th>预期效果</th></tr></thead><tbody><tr><td>购置私人笔记本</td><td>选择便携本，开始记录中长期目标</td><td>目标可视化管理</td></tr><tr><td>调整晨间习惯</td><td>7:00-8:00用于深度思考，推迟邮件处理</td><td>提升思考质量</td></tr><tr><td>约一位行业外朋友见面</td><td>从人脉中找出一位非技术领域人士</td><td>拓展视野</td></tr><tr><td>下班前整理第二天计划</td><td>每天离开前写下3项明日任务</td><td>减少早晨混乱</td></tr></tbody></table><h3 id="短期目标-一个月内" tabindex="-1">短期目标（一个月内） <a class="header-anchor" href="#短期目标-一个月内" aria-label="Permalink to &quot;短期目标（一个月内）&quot;">​</a></h3><ol><li><p><strong>建立&quot;三个关键&quot;发言习惯</strong></p><ul><li>每次会议发言前，先在纸上列出三个要点</li><li>练习用&quot;我认为......有三个关键&quot;开场</li><li>提升逻辑表达力和说服力</li></ul></li><li><p><strong>恢复英语学习</strong></p><ul><li>设定阶段性目标（托福900分方向）</li><li>每天接触英语材料30分钟</li><li>用商务英语场景练习而非纯语法</li></ul></li><li><p><strong>健康管理制度化</strong></p><ul><li>确定周末运动时段并向家人承诺</li><li>每天睡眠不少于6小时</li><li>开始早餐习惯</li></ul></li><li><p><strong>人脉拓展行动</strong></p><ul><li>每周至少安排一次公司外见面</li><li>主动联系一位前同事</li><li>参加一场行业外交流活动</li></ul></li></ol><h3 id="中期目标-三个月内" tabindex="-1">中期目标（三个月内） <a class="header-anchor" href="#中期目标-三个月内" aria-label="Permalink to &quot;中期目标（三个月内）&quot;">​</a></h3><ol><li><p><strong>职业方向探索</strong></p><ul><li>与至少5位不同行业人士交流</li><li>阅读3本非技术领域的商业书籍</li><li>在私人笔记中写下转型方向假设</li></ul></li><li><p><strong>思考习惯固化</strong></p><ul><li>遇到问题先思考5分钟再行动</li><li>每周用纸笔进行一次深度思考练习</li><li>用&quot;空→雨→伞&quot;框架分析三个实际问题</li></ul></li><li><p><strong>资料能力提升</strong></p><ul><li>手写草稿再数字化一个重要材料</li><li>用&quot;3W&quot;框架准备一次重要发言</li><li>践行&quot;注意细节&quot;原则</li></ul></li></ol><h3 id="长期目标-一年内" tabindex="-1">长期目标（一年内） <a class="header-anchor" href="#长期目标-一年内" aria-label="Permalink to &quot;长期目标（一年内）&quot;">​</a></h3><ol><li><p><strong>职业转型启动</strong></p><ul><li>确定转型方向并制定具体计划</li><li>积累新领域所需的知识和技能</li><li>在当前岗位留下可传承成果</li></ul></li><li><p><strong>人脉网络重构</strong></p><ul><li>建立新领域的初步人脉</li><li>维护好与前同事的关系</li><li>形成&quot;超越利害关系&quot;的深度友谊</li></ul></li><li><p><strong>家庭教育实践</strong></p><ul><li>将思考习惯、礼让精神传递给孩子</li><li>创造不同场景的家庭相处时光</li><li>帮助孩子建立健康习惯</li></ul></li></ol><hr><h2 id="附录-48个习惯速查清单" tabindex="-1">附录：48个习惯速查清单 <a class="header-anchor" href="#附录-48个习惯速查清单" aria-label="Permalink to &quot;附录：48个习惯速查清单&quot;">​</a></h2><h3 id="第一章-如何投资人脉-7个核心习惯" tabindex="-1">第一章：如何投资人脉（7个核心习惯） <a class="header-anchor" href="#第一章-如何投资人脉-7个核心习惯" aria-label="Permalink to &quot;第一章：如何投资人脉（7个核心习惯）&quot;">​</a></h3><ol><li>珍惜超越利害关系的人脉</li><li>在人脉上投资时间与金钱</li><li>记住对方名字（见面称呼三次）</li><li>真挚提问&quot;你来自哪里&quot;</li><li>清晰记住与对方相处的时间</li><li>变换场合加深关系</li><li>每周与公司外人士见一次面</li></ol><h3 id="第二章-磨炼内在与外在-11个核心习惯" tabindex="-1">第二章：磨炼内在与外在（11个核心习惯） <a class="header-anchor" href="#第二章-磨炼内在与外在-11个核心习惯" aria-label="Permalink to &quot;第二章：磨炼内在与外在（11个核心习惯）&quot;">​</a></h3><ol start="8"><li>礼让他人</li><li>多说&quot;谢谢&quot;少说&quot;对不起&quot;</li><li>培养思考无固定答案问题</li><li>读书后花三倍时间思考</li><li>读报纸思考&quot;大家的反应&quot;</li><li>重视坚定意见而非新颖想法</li><li>独立思考，不靠网络&quot;作弊&quot;</li><li>用&quot;So what?&quot;和&quot;Why so?&quot;思考</li><li>离开办公室带着笔和纸</li><li>用&quot;三个关键&quot;锻炼瞬间思考</li><li>养好身体，不迟到不缺席</li><li>注意健身，保持心灵年轻</li><li>服装整洁比个性更重要</li><li>两周护理一次鞋子</li></ol><h3 id="第三章-不被时间操纵-6个核心习惯" tabindex="-1">第三章：不被时间操纵（6个核心习惯） <a class="header-anchor" href="#第三章-不被时间操纵-6个核心习惯" aria-label="Permalink to &quot;第三章：不被时间操纵（6个核心习惯）&quot;">​</a></h3><ol start="22"><li>提前10分钟到场</li><li>周末自我投资（20多岁一天，30多岁半天）</li><li>清晨一小时高效工作（不先看邮件）</li><li>下班前整理第二天计划</li><li>周日晚上做好周一准备</li><li>工作忙时按优先程度和时间分类</li></ol><h3 id="第四章-决定性沟通-6个核心习惯" tabindex="-1">第四章：决定性沟通（6个核心习惯） <a class="header-anchor" href="#第四章-决定性沟通-6个核心习惯" aria-label="Permalink to &quot;第四章：决定性沟通（6个核心习惯）&quot;">​</a></h3><ol start="28"><li>笔记本随时可打开</li><li>接到任务当场确认（5W1H）</li><li>接到任务5分钟内开始安排</li><li>回复邮件速度=评价</li><li>汇报联系交谈先发制人</li><li>用假设说服对方</li><li>让繁忙上司挤出时间</li><li>第二天一早汇报进展</li></ol><h3 id="第五章-资料与会议贡献-7个核心习惯" tabindex="-1">第五章：资料与会议贡献（7个核心习惯） <a class="header-anchor" href="#第五章-资料与会议贡献-7个核心习惯" aria-label="Permalink to &quot;第五章：资料与会议贡献（7个核心习惯）&quot;">​</a></h3><ol start="36"><li>资料视作&quot;自己的产品&quot;</li><li>颜色控制在三种以内</li><li>准备资料要有&quot;3W&quot;意识</li><li>手写草稿再数字化</li><li>不局限于&quot;一张表格一条信息&quot;</li><li>贯彻注意细节</li><li>会议不发言等于缺席</li><li>坐在白板前整理讨论</li></ol><h3 id="第六章-全球化职业技能-5个核心习惯" tabindex="-1">第六章：全球化职业技能（5个核心习惯） <a class="header-anchor" href="#第六章-全球化职业技能-5个核心习惯" aria-label="Permalink to &quot;第六章：全球化职业技能（5个核心习惯）&quot;">​</a></h3><ol start="44"><li>健全爱国心转化为动力</li><li>英语逻辑性比流利重要</li><li>托福900分是商务英语入门</li><li>工作以更高标准要求自己</li><li>辞职要&quot;毕业&quot;而非&quot;退学&quot;</li></ol><hr><h2 id="金句摘录" tabindex="-1">金句摘录 <a class="header-anchor" href="#金句摘录" aria-label="Permalink to &quot;金句摘录&quot;">​</a></h2><blockquote><p>&quot;读书，举一反三，加以实践。&quot; —— 作者序言</p></blockquote><blockquote><p>&quot;你要相信某些东西——直觉、命运、人生、缘分......&quot; —— 乔布斯演讲引用</p></blockquote><blockquote><p>&quot;读完书之后，要花三倍的时间来思考。&quot; —— 麦肯锡大前研一</p></blockquote><blockquote><p>&quot;空→雨→伞：天上堆积云→可能会下雨→出门带伞&quot; —— 麦肯锡思考模式</p></blockquote><blockquote><p>&quot;回复邮件的速度=别人对你的评价。&quot; —— 高盛实践</p></blockquote><blockquote><p>&quot;会议不发言，等于缺席。&quot; —— 麦肯锡会议观</p></blockquote><blockquote><p>&quot;辞职不是退学，要争取毕业。&quot; —— 职业转换心态</p></blockquote><hr><p><em>笔记整理时间：2026年7月13日</em><em>适用场景：职场转型、中年职业规划、效率提升、家庭平衡</em></p>',88)])])}const c=i(u,[["render",r]]);export{p as __pageData,c as default};
